function o(t){if(!t&&t!==0)return"-";const r=["B","KB","MB","GB","TB","PB"];let e=0,n=t;for(;n>=1024&&e<r.length-1;)n/=1024,e++;return`${n.toFixed(n>=100||e===0?0:1)} ${r[e]}`}function i(t){return`${o(t)}/s`}function u(t){if(!t)return"-";const r=Math.floor(t/86400),e=Math.floor(t%86400/3600),n=Math.floor(t%3600/60);return r>0?`${r}天 ${e}小时`:e>0?`${e}小时 ${n}分`:`${n}分`}function a(t){return`${(t||0).toFixed(1)}%`}function c(t){return t?new Date(t*1e3).toLocaleString():"-"}function l(t){return t>=90?"crit":t>=70?"warn":""}const f=["#3b82f6","#22c55e","#eab308","#ef4444","#a855f7","#06b6d4","#f97316","#ec4899"];function s(t){let r=0;for(let e=0;e<t.length;e++)r=r*31+t.charCodeAt(e)>>>0;return f[r%f.length]}export{o as a,l as b,i as c,u as d,c as e,a as f,s as t};
